		<set-variable name="rawForm" value="@((string)context.Request.Body.As(preserveContent: true) ?? string.Empty)" />


		<set-variable name="response_type" value="@{  
        var raw = (string)context.Variables["rawForm"] ?? string.Empty;  
        var key = "response_type=";  
        var i = raw.IndexOf(key, StringComparison.OrdinalIgnoreCase);  
        var result = "";  
        if (i >= 0) {  
          var s = i + key.Length;  
          var e = raw.IndexOf('&', s);  
          var v = (e < 0 ? raw.Substring(s) : raw.Substring(s, e - s));  
          v = v.Replace("+", " ");  
          result = System.Uri.UnescapeDataString(v);  
        }  
        return result;  
      }" />

