				<set-variable name="tokenId" value="@{   
                    var token = "";   
                    var resp = context.Variables.ContainsKey("authResp") ? (IResponse)context.Variables["authResp"] : null;   
                    if (resp != null) {   
                        try {   
                            var jo = resp.Body.As();   
                            token = (string)(jo?["tokenId"]) ?? "";    
                        } catch {}   
                    }   
                    return token;   
                }" />






